    83→// EncodeReadResponse writes a remote.Response to a http.ResponseWriter.
    84→func EncodeReadResponse(resp *prompb.ReadResponse, w http.ResponseWriter) error {
    85→	data, err := proto.Marshal(resp)
    86→	if err != nil {
    87→		return err
    88→	}
    89→
    90→	compressed := snappy.Encode(nil, data)
    91→	_, err = w.Write(compressed)
    92→	return err
    93→}
