   198→// NegotiateResponseType returns first accepted response type that this server supports.
   199→// On the empty accepted list we assume that the SAMPLES response type was requested. This is to maintain backward compatibility.
   200→func NegotiateResponseType(accepted []prompb.ReadRequest_ResponseType) (prompb.ReadRequest_ResponseType, error) {
   201→	if len(accepted) == 0 {
   202→		accepted = []prompb.ReadRequest_ResponseType{prompb.ReadRequest_SAMPLES}
   203→	}
   204→
   205→	supported := map[prompb.ReadRequest_ResponseType]struct{}{
   206→		prompb.ReadRequest_SAMPLES:             {},
   207→		prompb.ReadRequest_STREAMED_XOR_CHUNKS: {},
   208→	}
   209→
   210→	for _, resType := range accepted {
   211→		if _, ok := supported[resType]; ok {
   212→			return resType, nil
   213→		}
   214→	}
   215→	return 0, fmt.Errorf("server does not support any of the requested response types: %v; supported: %v", accepted, supported)
   216→}
